using System;namespace BgCommon.UI.Designer.Plugins{    /// <summary>    /// 插件服务    /// </summary>    public class PluginService    {        private readonly PluginManager _pluginManager;        private readonly string _pluginDirectory;                /// <summary>        /// 插件管理器        /// </summary>        public PluginManager PluginManager => _pluginManager;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        /// <param name="pluginDirectory">插件目录</param>        public PluginService(ICSharpCode.WpfDesign.DesignContext context, string pluginDirectory = "Plugins")        {            _pluginManager = new PluginManager(context);            _pluginDirectory = pluginDirectory;        }                /// <summary>        /// 初始化插件服务        /// </summary>        public void Initialize()        {            // 发现并加载插件            _pluginManager.DiscoverPlugins(_pluginDirectory);        }                /// <summary>        /// 关闭插件服务        /// </summary>        public void Shutdown()        {            // 卸载所有插件            _pluginManager.UnloadAllPlugins();        }    }}